import { api } from './client'

export type FeatureFlags = Record<string, boolean>

export interface BrandingConfig {
  logoUrl?: string
  primaryColor?: string
  accentColor?: string
  organizationName?: string
  faviconUrl?: string
}

export interface TenantConfigDto {
  id: string
  tenantId: string
  features: FeatureFlags
  branding: BrandingConfig
  createdAt: string
  updatedAt: string
}

export function fetchTenantConfig(tenantId: string): Promise<TenantConfigDto | null> {
  return api.get<TenantConfigDto | null>(`/admin/tenants/${encodeURIComponent(tenantId)}/config`)
    .catch(() => ({
      id: 'demo', tenantId, features: {}, branding: {},
      createdAt: new Date().toISOString(), updatedAt: new Date().toISOString(),
    } as TenantConfigDto))
}

export function upsertTenantConfig(
  tenantId: string,
  patch: { features?: FeatureFlags; branding?: BrandingConfig },
): Promise<TenantConfigDto> {
  return api.patch<TenantConfigDto>(`/admin/tenants/${encodeURIComponent(tenantId)}/config`, patch)
}
