/**
 * Tenant editor — feature flags + branding (B2B / white-label).
 * Phase 0.1+0.3.
 */

import { useEffect, useState } from 'react'
import PlatformShell from '../components/PlatformShell'
import { useToast } from '../hooks/useToast'
import { fetchTenantConfig, upsertTenantConfig, type TenantConfigDto, type FeatureFlags, type BrandingConfig } from '../api/tenantConfig'

const DEFAULT_FLAGS: { key: string; label: string; hint: string }[] = [
  { key: 'scratch',         label: '🎮 Scratch-трек',          hint: 'Показывать ли карточки и тренажёры Scratch ученикам' },
  { key: 'python',          label: '🐍 Python-трек',           hint: 'IDE на Pyodide + черепашка' },
  { key: 'vibe',            label: '🌐 Vibe-coding',           hint: 'HTML/CSS/JS трек' },
  { key: 'studio',          label: '🧱 Студия (3D)',           hint: 'Three.js игровой редактор' },
  { key: 'sites',           label: '🌐 Конструктор сайтов',    hint: 'SitesHub + SiteEditor' },
  { key: 'leagues',         label: '🏆 Лиги',                  hint: 'Соревнования между классами' },
  { key: 'achievements',    label: '🎖️ Ачивки',                hint: 'Тосты с достижениями' },
  { key: 'streak',          label: '🔥 Стрики',                hint: 'Виджет ежедневного прогресса' },
  { key: 'parent',          label: '👨‍👩‍👦 Кабинет родителя',     hint: 'Доступ к /parent' },
  { key: 'liveStreams',     label: '🎥 LiveKit-занятия',       hint: 'Видео-комнаты' },
  { key: 'booking',         label: '📅 Публичный booking',     hint: 'Виджет /book для родителей с улицы' },
  { key: 'chat',            label: '💬 Чат',                   hint: 'Чат учителя с учеником/родителем' },
]

export default function AdminTenant() {
  const { toast, show } = useToast()
  const [tenantId, setTenantId] = useState('default')
  const [config, setConfig] = useState<TenantConfigDto | null>(null)
  const [loading, setLoading] = useState(false)
  const [saving, setSaving] = useState(false)

  const [features, setFeatures] = useState<FeatureFlags>({})
  const [branding, setBranding] = useState<BrandingConfig>({})

  function load() {
    setLoading(true)
    fetchTenantConfig(tenantId)
      .then((cfg) => {
        setConfig(cfg)
        setFeatures(cfg?.features ?? {})
        setBranding(cfg?.branding ?? {})
      })
      .catch(() => show('Ошибка загрузки', 'error'))
      .finally(() => setLoading(false))
  }

  useEffect(load, [tenantId])

  async function handleSave() {
    setSaving(true)
    try {
      const updated = await upsertTenantConfig(tenantId, { features, branding })
      setConfig(updated)
      show('Сохранено', 'success')
    } catch (e) {
      show('Ошибка: ' + (e instanceof Error ? e.message : ''), 'error')
    } finally {
      setSaving(false)
    }
  }

  function toggleFlag(key: string) {
    setFeatures((prev) => ({ ...prev, [key]: !prev[key] }))
  }

  return (
    <PlatformShell activeKey="admin">
      {toast && (
        <div role="status" style={{ position: 'fixed', top: 20, right: 20, zIndex: 9999, background: toast.kind === 'error' ? '#dc2626' : toast.kind === 'success' ? '#059669' : '#6b5ce7', color: '#fff', padding: '10px 20px', borderRadius: 12, fontSize: 14, fontWeight: 600 }}>{toast.msg}</div>
      )}

      <div className="kb-cover kb-cover--violet">
        <div style={{ display: 'flex', alignItems: 'center', gap: 12 }}>
          <span style={{ fontSize: 36 }} aria-hidden>🏢</span>
          <div>
            <div className="eyebrow" style={{ color: 'rgba(255,255,255,0.7)' }}>White-label · B2B</div>
            <h1 className="h1" style={{ margin: 0, color: '#fff' }}>Конфиг арендатора</h1>
          </div>
        </div>
      </div>

      <div style={{ maxWidth: 900, margin: '0 auto', padding: '28px 16px', display: 'flex', flexDirection: 'column', gap: 20 }}>

        {/* Tenant selector */}
        <div className="kb-card" style={{ padding: 20, display: 'flex', gap: 12, alignItems: 'center', flexWrap: 'wrap' }}>
          <label style={{ ...lbl, marginBottom: 0 }}>Tenant:</label>
          <input style={{ ...inp, width: 240, marginBottom: 0 }} value={tenantId} onChange={(e) => setTenantId(e.target.value)} placeholder="default" />
          <button className="kb-btn" onClick={load}>↻ Загрузить</button>
          {config && (
            <span style={{ fontSize: 12, color: 'var(--ink-soft)', marginLeft: 'auto' }}>
              Обновлён: {new Date(config.updatedAt).toLocaleString('ru-RU')}
            </span>
          )}
        </div>

        {loading ? (
          <div className="kb-card" style={{ padding: 40, textAlign: 'center', color: 'var(--ink-soft)' }}>Загрузка…</div>
        ) : (
          <>
            {/* Feature flags */}
            <div className="kb-card" style={{ padding: 24 }}>
              <h2 style={{ margin: '0 0 16px', fontSize: 18, fontWeight: 800 }}>Feature flags</h2>
              <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(280px, 1fr))', gap: 10 }}>
                {DEFAULT_FLAGS.map((f) => {
                  const enabled = !!features[f.key]
                  return (
                    <label key={f.key} style={{ display: 'flex', gap: 10, padding: 12, borderRadius: 10, background: enabled ? 'var(--mint-soft, #d1fae5)' : 'var(--paper-2, #f9f8ff)', cursor: 'pointer', border: enabled ? '1.5px solid var(--mint-ink, #065f46)' : '1.5px solid transparent' }}>
                      <input type="checkbox" checked={enabled} onChange={() => toggleFlag(f.key)} style={{ marginTop: 3 }} />
                      <div style={{ flex: 1 }}>
                        <div style={{ fontWeight: 700, fontSize: 13 }}>{f.label}</div>
                        <div style={{ fontSize: 11, color: 'var(--ink-soft)', marginTop: 2 }}>{f.hint}</div>
                      </div>
                    </label>
                  )
                })}
              </div>

              {/* Custom flag */}
              <div style={{ marginTop: 16, padding: 12, background: 'var(--paper-2)', borderRadius: 8 }}>
                <div style={{ fontSize: 11, fontWeight: 700, color: 'var(--ink-soft)', marginBottom: 6 }}>Произвольный флаг (raw JSON):</div>
                <textarea
                  style={{ ...inp, fontFamily: 'monospace', fontSize: 12, minHeight: 80 }}
                  value={JSON.stringify(features, null, 2)}
                  onChange={(e) => {
                    try { setFeatures(JSON.parse(e.target.value)) } catch { /* ignore */ }
                  }}
                />
              </div>
            </div>

            {/* Branding */}
            <div className="kb-card" style={{ padding: 24 }}>
              <h2 style={{ margin: '0 0 16px', fontSize: 18, fontWeight: 800 }}>Брендинг</h2>
              <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 12 }}>
                <div>
                  <label style={lbl}>Название организации</label>
                  <input style={inp} value={branding.organizationName ?? ''} onChange={(e) => setBranding({ ...branding, organizationName: e.target.value })} placeholder="Eduson Kids" />
                </div>
                <div>
                  <label style={lbl}>Logo URL</label>
                  <input style={inp} value={branding.logoUrl ?? ''} onChange={(e) => setBranding({ ...branding, logoUrl: e.target.value })} placeholder="https://..." />
                </div>
                <div>
                  <label style={lbl}>Favicon URL</label>
                  <input style={inp} value={branding.faviconUrl ?? ''} onChange={(e) => setBranding({ ...branding, faviconUrl: e.target.value })} placeholder="https://..." />
                </div>
                <div>
                  <label style={lbl}>Primary (hex)</label>
                  <div style={{ display: 'flex', gap: 8 }}>
                    <input style={{ ...inp, flex: 1 }} value={branding.primaryColor ?? ''} onChange={(e) => setBranding({ ...branding, primaryColor: e.target.value })} placeholder="#6b5ce7" />
                    {branding.primaryColor && <div style={{ width: 40, borderRadius: 8, background: branding.primaryColor }} />}
                  </div>
                </div>
                <div>
                  <label style={lbl}>Accent (hex)</label>
                  <div style={{ display: 'flex', gap: 8 }}>
                    <input style={{ ...inp, flex: 1 }} value={branding.accentColor ?? ''} onChange={(e) => setBranding({ ...branding, accentColor: e.target.value })} placeholder="#3ab97a" />
                    {branding.accentColor && <div style={{ width: 40, borderRadius: 8, background: branding.accentColor }} />}
                  </div>
                </div>
              </div>
            </div>

            {/* Preview */}
            {(branding.organizationName || branding.primaryColor) && (
              <div className="kb-card" style={{ padding: 24, background: branding.primaryColor ?? 'var(--violet)', color: '#fff' }}>
                <div style={{ fontSize: 13, opacity: 0.8, marginBottom: 4 }}>Предпросмотр:</div>
                <h3 style={{ margin: 0, fontSize: 28, fontWeight: 900, fontFamily: 'var(--f-display)' }}>
                  {branding.organizationName || 'Eduson Kids'}
                </h3>
              </div>
            )}

            <div style={{ display: 'flex', gap: 8, justifyContent: 'flex-end' }}>
              <button className="kb-btn" style={{ background: 'var(--violet)', color: '#fff', fontWeight: 800 }} onClick={() => void handleSave()} disabled={saving}>
                {saving ? '…' : '💾 Сохранить'}
              </button>
            </div>
          </>
        )}
      </div>
    </PlatformShell>
  )
}

const lbl: React.CSSProperties = { display: 'block', fontSize: 11, fontWeight: 700, letterSpacing: 1, textTransform: 'uppercase', color: 'var(--ink-soft)', marginBottom: 4 }
const inp: React.CSSProperties = { width: '100%', padding: '8px 12px', borderRadius: 8, border: '1px solid var(--paper-3)', fontSize: 14, fontFamily: 'inherit', boxSizing: 'border-box' }
